  ('social-worker-moex-07340', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '商業組織與社會服務組織在績效管理的差異上，下列描述何者錯誤？', '["商業組織注重效率（Efficiency）與效果（Effectiveness），社會服務組織除了效率、效果之外，也常須 注意公平（Equity）", "商業組織績效容易衡量；社會服務組織績效不易衡量", "商業組織與社會服務組織的績效管理原則並無差異，彼此可互相適用", "商業組織的績效常以貨幣來衡量；社會服務組織績效常以其公益目標來衡量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
